import{_ as o,o as t,c as d,a2 as a}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"공통코드 관리 화면 가져오기 — 백엔드는 그대로, 프론트만 lego 이식","description":"","frontmatter":{"slug":"code-management-parity","title":"공통코드 관리 화면 가져오기 — 백엔드는 그대로, 프론트만 lego 이식","authors":[],"tags":["frontend","vue","vuetify","vitest","admin","code","common-code","feature-016"],"created":"2026-06-10 20:45 (KST)","date":"2026-06-10T11:45:00.000Z"},"headers":[],"relativePath":"journal/2026-06-10-code-management-parity.md","filePath":"journal/2026-06-10-code-management-parity.md","lastUpdated":1781092690000}'),c={name:"journal/2026-06-10-code-management-parity.md"};function r(i,e,n,s,l,u){return t(),d("div",null,[...e[0]||(e[0]=[a('<p>관리자 콘솔에는 <a href="./2026-06-07-menu-parity">메뉴 관리를 lego 와 맞춘</a> 데 이어, 정작 <strong>공통코드(코드 그룹·항목) 관리 화면이 없었다.</strong> 백엔드(<code>/api/v1/codes</code>)는 feature 004 때 이미 있었는데 화면만 비어 있던 것. Spec Kit 사이클로 lego 의 공통코드 2화면 + 재사용 드롭다운을 <strong>프론트만</strong> 이식했다 — 백엔드는 한 줄도 건드리지 않는 범위.</p><h2 id="무엇이-달랐나" tabindex="-1">무엇이 달랐나 <a class="header-anchor" href="#무엇이-달랐나" aria-label="Permalink to &quot;무엇이 달랐나&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>이전(006)</th><th>lego(기준)</th></tr></thead><tbody><tr><td>공통코드 화면</td><td><strong>없음</strong></td><td>그룹 목록 / 항목 목록 2화면 + <code>CodeSelect</code></td></tr><tr><td>백엔드</td><td><code>/api/v1/codes</code> <strong>이미 있음</strong></td><td><code>com.clear.code</code></td></tr><tr><td>항목 필드</td><td><code>codeLabel</code>·<code>extra1·2</code></td><td><code>codeName</code>·<code>attr1·2·3</code></td></tr></tbody></table><h2 id="결정-—-프론트만-백엔드는-손대지-않는다" tabindex="-1">결정 — 프론트만, 백엔드는 손대지 않는다 <a class="header-anchor" href="#결정-—-프론트만-백엔드는-손대지-않는다" aria-label="Permalink to &quot;결정 — 프론트만, 백엔드는 손대지 않는다&quot;">​</a></h2><p>clarify 에서 두 가지를 못 박았다: ① <strong>정합 깊이 = 프론트만 이식</strong>(기존 백엔드 재사용), ② <code>CodeSelect</code> 재사용 컴포넌트 <strong>포함</strong>. lego 화면을 그대로 베끼지 않고, 화면·타입을 <strong>현행 백엔드 DTO 기준</strong>(<code>codeLabel</code>·<code>extra1</code>·<code>extra2</code>, 확장속성 2개)으로 적응했다. lego 의 <code>codeName</code>/<code>attr3</code> 는 버렸다 — 단일 출처는 백엔드다.</p><h2 id="한-일" tabindex="-1">한 일 <a class="header-anchor" href="#한-일" aria-label="Permalink to &quot;한 일&quot;">​</a></h2><ul><li><strong>타입·API</strong>: <code>types/models.ts</code> 에 <code>CodeGroup*</code>/<code>CodeDetail*</code> 4개, <code>api/codes.ts</code>(그룹· 항목 CRUD, <code>unwrap</code> 패턴).</li><li><strong>화면 2장</strong>: <code>CodeGroupsView</code>(검색·CRUD, 행 클릭 → 항목) + <code>CodeDetailsView</code> (그룹별 항목 CRUD). <code>DeptsView</code> 관례(<code>v-table</code> + <code>v-dialog</code> 폼 + native <code>confirm</code>)를 따라 다른 관리 화면과 시각 일관.</li><li><strong>CodeSelect</strong>: 그룹의 <strong>활성(useYn=&#39;Y&#39;) 항목만</strong> 드롭다운으로 노출하는 재사용 컴포넌트.</li><li><strong>라우트·네비</strong>: <code>/admin/codes</code>, <code>/admin/codes/:groupCode</code> + 셸 네비 &quot;공통코드&quot; 하드코딩.</li></ul><h2 id="까다로웠던-지점" tabindex="-1">까다로웠던 지점 <a class="header-anchor" href="#까다로웠던-지점" aria-label="Permalink to &quot;까다로웠던 지점&quot;">​</a></h2><h3 id="_1-그룹-삭제가-항목까지-지운다-—-경고를-붙였다" tabindex="-1">1. 그룹 삭제가 항목까지 지운다 — 경고를 붙였다 <a class="header-anchor" href="#_1-그룹-삭제가-항목까지-지운다-—-경고를-붙였다" aria-label="Permalink to &quot;1. 그룹 삭제가 항목까지 지운다 — 경고를 붙였다&quot;">​</a></h3><p>백엔드 <code>deleteGroup</code> 은 <code>deleteDetailsByGroup</code> 으로 하위 항목을 <strong>cascade 삭제</strong>한다 (고아 항목 방지). lego 원본 삭제 다이얼로그는 이를 경고하지 않는데, 그대로 두면 사용자가 모르고 항목을 통째로 날린다. 삭제 confirm 문구에 &quot;코드 항목도 함께 삭제됩니다&quot;를 명시했다.</p><h3 id="_2-vitest-에서-vuetify-컴포넌트가-css-로-깨진다" tabindex="-1">2. Vitest 에서 Vuetify 컴포넌트가 <code>.css</code> 로 깨진다 <a class="header-anchor" href="#_2-vitest-에서-vuetify-컴포넌트가-css-로-깨진다" aria-label="Permalink to &quot;2. Vitest 에서 Vuetify 컴포넌트가 `.css` 로 깨진다&quot;">​</a></h3><p><code>CodeSelect.spec.ts</code> 가 SFC 를 import 하니 vite-plugin-vuetify 의 autoImport 가 끼워넣은 <code>VSelect.css</code> 사이드이펙트를 Node 가 못 읽어 <code>Unknown file extension &quot;.css&quot;</code> 로 죽었다. 이 저장소의 첫 컴포넌트 테스트라 인프라가 없던 것. <code>vite.config.ts</code> 의 test 블록에 <code>server.deps.inline: [&#39;vuetify&#39;]</code> 를 더해 vite 가 vuetify 를 변환(=CSS 무해 처리)하게 했다. 테스트 자체는 <code>v-select</code> 를 가벼운 스텁으로 갈아끼워 props/emit 만 검증한다.</p><h3 id="_3-vi-mock-팩토리는-호이스팅된다" tabindex="-1">3. <code>vi.mock</code> 팩토리는 호이스팅된다 <a class="header-anchor" href="#_3-vi-mock-팩토리는-호이스팅된다" aria-label="Permalink to &quot;3. `vi.mock` 팩토리는 호이스팅된다&quot;">​</a></h3><p><code>const get = vi.fn()</code> 을 선언하고 <code>vi.mock</code> 팩토리에서 참조했더니 &quot;Cannot access &#39;get&#39; before initialization&quot;. 팩토리가 파일 최상단으로 끌어올려지기 때문. <code>vi.hoisted(() =&gt; ...)</code> 로 mock 함수를 같이 끌어올려 해결.</p><h2 id="결과" tabindex="-1">결과 <a class="header-anchor" href="#결과" aria-label="Permalink to &quot;결과&quot;">​</a></h2><ul><li>프론트 <code>vue-tsc + vite build</code> <strong>통과</strong>, 단위테스트 <strong>23/23</strong>(코드 API 8 + CodeSelect 2 신규).</li><li>백엔드는 <strong>무변경</strong> — 회귀 표면을 프론트로 한정.</li><li>단, <strong>브라우저 픽셀 대조는 미실시</strong>(백엔드 기동 필요) — <code>npm run dev</code> 로 눈 확인 권장.</li></ul><p>규약·설계는 <code>specs/016-code-management-parity/</code>.</p>',17)])])}const p=o(c,[["render",r]]);export{h as __pageData,p as default};
